// Compute previous calendar month in Asia/Taipei.
const now = new Date();
const fmt = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Taipei', year: 'numeric', month: '2-digit', day: '2-digit' });
const todayParts = fmt.formatToParts(now).reduce((acc,p) => { if (p.type !== 'literal') acc[p.type] = p.value; return acc; }, {});
const yr = Number(todayParts.year), mo = Number(todayParts.month);
const prevYr = mo === 1 ? yr - 1 : yr;
const prevMo = mo === 1 ? 12 : mo - 1;
const yyyymm = `${prevYr}-${String(prevMo).padStart(2,'0')}`;
const rangeStart = `${yyyymm}-01`;
const rangeEndExclusive = `${yr}-${String(mo).padStart(2,'0')}-01`;
return [{ json: { correlationId: `monthly-${yyyymm}-${Math.floor(Math.random()*1e6)}`, yyyymm, rangeStart, rangeEndExclusive } }];

const range = $node['Stamp previous month (Taipei)'].json;
const rows = $items().map(i => i.json).filter(r => {
  const t = (r.appliedAt || '').slice(0,10);
  return t >= range.rangeStart && t < range.rangeEndExclusive;
});
const headers = ['correlationId','op','provider','orderId','invoiceNumber','status','appliedAt'];
const escape = (v) => {
  const s = v == null ? '' : String(v);
  if (/[,"\n]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
};
const lines = [headers.join(',')];
for (const r of rows) lines.push(headers.map(h => escape(r[h])).join(','));
const counts = rows.reduce((acc,r) => { acc[r.op] = (acc[r.op]||0) + 1; return acc; }, {});
return [{ json: { correlationId: range.correlationId, yyyymm: range.yyyymm, csv: lines.join('\n'), rowCount: rows.length, counts } }];

